<?php
namespace App\Filament\Resources\CVS\RelationManagers;
use Filament\Actions\ViewAction; use Filament\Resources\RelationManagers\RelationManager; use Filament\Tables\Columns\TextColumn; use Filament\Tables\Filters\SelectFilter; use Filament\Tables\Table;
class HistoriesRelationManager extends RelationManager { protected static string $relationship = 'histories'; protected static ?string $title = 'History'; public function table(Table $table): Table { return $table->columns([TextColumn::make('user.name')->label('User')->searchable(), TextColumn::make('action')->badge()->searchable()->sortable(), TextColumn::make('notes')->limit(60)->placeholder('—'), TextColumn::make('created_at')->label('Created')->dateTime('d M Y, H:i')->sortable()])->filters([SelectFilter::make('action')->options(fn () => $this->getRelationship()->distinct()->pluck('action', 'action')->all())])->recordActions([ViewAction::make()])->defaultSort('created_at', 'desc')->emptyStateHeading('No history recorded'); } }
